export class FormInputComponent implements OnInit, ControlValueAccessor {
  id = input('');
  name = input('');
  type = input('');
  required = input(false);
  placeholder = input('');
  style = input('');

  formControl!: FormControl;
  onTouched: any;
  onChange: any;

  ngOnInit(): void {
    const validators: ValidatorFn[] = [];

    if (this.required()) {
      validators.push(Validators.required);
    }

    if (this.type() === 'email') {
